foreach ($Path in $Files.Keys) {
    $Directory = Split-Path $Path -Parent
    if ($Directory -and -not (Test-Path $Directory)) {
        New-Item -ItemType Directory -Force -Path $Directory | Out-Null
    }
    $Bytes = [System.Convert]::FromBase64String($Files[$Path])
    [System.IO.File]::WriteAllBytes((Join-Path $RepoRoot $Path), $Bytes)
    Write-Host "WRITE_OK: $Path"
}

Write-Host "=== STRUCTURE CHECK ==="
$RequiredPaths = @(
    "README.md",
    "AGENTS.md",
    "AGENT_MISSION.md",
    "GENESIS_MASTER_PLAN.md",
    "CAPABILITY_ROADMAP.json",
    "GENESIS_STATE.json",
    "TASK_QUEUE.json",
    "contracts/capability_roadmap.schema.json",
    "contracts/genesis_state.schema.json",
    "contracts/task_queue.schema.json",
    "contracts/build_task.schema.json",
    "contracts/run_report.schema.json",
    "contracts/validation_report.schema.json",
    "contracts/external_agent_spec.schema.json",
    "orchestrator/run.ps1",
    "modules/read_genesis_plan.ps1",
    "modules/read_genesis_state.ps1",
    "modules/select_next_task.ps1",
    "modules/execute_build_task.ps1",
    "modules/run_validators.ps1",
    "modules/update_genesis_state.ps1",
    "modules/update_task_queue.ps1",
    "modules/emit_run_report.ps1",
    "validators/validate_repo_genesis.ps1",
    "validators/validate_state_alignment.ps1",
    "validators/validate_task_queue_alignment.ps1",
    "validators/validate_run_report_contract.ps1",
    "validators/validate_external_agent_spec.ps1",
    "specs/external_agent_spec_template/MISSION.md",
    "specs/external_agent_spec_template/INPUT_CONTRACT.json",
    "specs/external_agent_spec_template/OUTPUT_CONTRACT.json",
    "specs/external_agent_spec_template/CAPABILITY_REQUIREMENTS.json",
    "specs/external_agent_spec_template/VALIDATION_REQUIREMENTS.md",
    "specs/external_agent_spec_template/FORBIDDEN_SCOPE.md",
    "runs/.gitkeep",
    "generated_agents/.gitkeep"
)
$Missing = @()
foreach ($Path in $RequiredPaths) {
    if (Test-Path $Path) { Write-Host "PASS: $Path" } else { Write-Host "FAIL: $Path"; $Missing += $Path }
}
if ($Missing.Count -gt 0) {
    Write-Host "GENESIS_SKELETON_CHECK=FAIL"
    Write-Host "MISSING_COUNT=$($Missing.Count)"
    throw "Genesis skeleton missing required files."
}
Write-Host "GENESIS_SKELETON_CHECK=PASS"

Write-Host "=== JSON PARSE CHECK ==="
$JsonFiles = @("CAPABILITY_ROADMAP.json","GENESIS_STATE.json","TASK_QUEUE.json") + (Get-ChildItem "contracts" -Filter "*.json" | ForEach-Object { $_.FullName }) + (Get-ChildItem "specs/external_agent_spec_template" -Filter "*.json" | ForEach-Object { $_.FullName })
foreach ($JsonPath in $JsonFiles) {
    $null = Get-Content -Raw $JsonPath | ConvertFrom-Json
    Write-Host "JSON_OK: $JsonPath"
}
Write-Host "JSON_PARSE_CHECK=PASS"

Write-Host "=== GIT COMMIT ==="
git add .
git commit -m "Initialize Agent Builder genesis skeleton"
if ($LASTEXITCODE -ne 0) { throw "git commit failed. Review git identity or repository state." }
Write-Host "COMMIT_STATUS=PASS"
git log --oneline -1
Write-Host "=== AGENT BUILDER GENESIS BOOTSTRAP COMPLETE ==="
